import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { returnsService } from '../services/returns';
import { Card, Table, StatusBadge, RiskBar, LoadingScreen, Alert, Button } from '../components/UI';
import { formatDate, formatReason, getErrorMessage } from '../utils/helpers';
import { PlusCircle, ChevronRight, Inbox } from 'lucide-react';

export default function MyReturns() {
  const [returns, setReturns] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    returnsService.myReturns()
      .then(r => setReturns(r.data))
      .catch(e => setError(getErrorMessage(e)))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <LoadingScreen />;

  return (
    <div className="max-w-5xl mx-auto px-4 py-8 animate-fade-in">
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="font-display text-2xl font-bold text-slate-900">My Returns</h1>
          <p className="text-slate-500 text-sm mt-1">{returns.length} total requests</p>
        </div>
        <Link to="/customer/create-return">
          <Button icon={PlusCircle}>New Request</Button>
        </Link>
      </div>

      {error && <Alert type="error" message={error} className="mb-4" />}

      <Card>
        {returns.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-16 gap-3">
            <Inbox className="w-10 h-10 text-slate-300" />
            <p className="font-medium text-slate-400">No return requests yet</p>
            <Link to="/customer/create-return">
              <Button variant="secondary" size="sm">Create your first return</Button>
            </Link>
          </div>
        ) : (
          <Table headers={['Order ID', 'Product', 'Reason', 'Risk Score', 'Status', 'Date', '']}>
            {returns.map(r => (
              <tr key={r.id} className="border-b border-slate-50 hover:bg-slate-50/50 transition-colors group">
                <td className="px-4 py-3">
                  <span className="font-mono text-xs font-medium text-slate-700 bg-slate-100 px-2 py-0.5 rounded">
                    #{r.order_id}
                  </span>
                </td>
                <td className="px-4 py-3 text-sm font-medium text-slate-800 max-w-[160px] truncate">
                  {r.product_name}
                </td>
                <td className="px-4 py-3 text-xs text-slate-500">{formatReason(r.return_reason)}</td>
                <td className="px-4 py-3 w-36"><RiskBar score={r.risk_score} /></td>
                <td className="px-4 py-3"><StatusBadge status={r.status} /></td>
                <td className="px-4 py-3 text-xs text-slate-400">{formatDate(r.created_at)}</td>
                <td className="px-4 py-3">
                  <Link
                    to={`/customer/return/${r.id}`}
                    className="opacity-0 group-hover:opacity-100 transition-opacity inline-flex items-center gap-1 text-xs font-semibold text-brand-600 hover:text-brand-800"
                  >
                    View <ChevronRight className="w-3 h-3" />
                  </Link>
                </td>
              </tr>
            ))}
          </Table>
        )}
      </Card>
    </div>
  );
}
